'use strict';

const test = require('node:test');
const assert = require('node:assert/strict');
const { buildEnvelope } = require('../src/job_envelope');

test('the envelope preserves explicit zero and false metadata', () => {
  const envelope = buildEnvelope({ kind: 'sync', id: 's-1' }, {
    attempt: 0,
    traceSampled: false,
  });
  assert.equal(Object.hasOwn(envelope, 'attempt'), true);
  assert.equal(Object.hasOwn(envelope, 'traceSampled'), true);
  assert.equal(envelope.attempt, 0);
  assert.equal(envelope.traceSampled, false);
});
